import React from "react";

const Header = () => {
  return (
    <div className="header bg-blue-700 text-white p-4 flex justify-between items-center shadow-md">
      <h2 className="text-xl font-bold">PeerCollab</h2>
      <div className="header-buttons flex gap-2">
        <button className="dashboard-btn bg-blue-500 px-4 py-2 rounded hover:bg-blue-600">
          Dashboard
        </button>
        <button className="signout-btn bg-red-500 px-4 py-2 rounded hover:bg-red-600">
          Sign Out
        </button>
      </div>
    </div>
  );
};

export default Header;
